import java.util.Scanner;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        int maxLength = Math.min(name.length(), 10); // Ensure input does not exceed buffer size
        char[] buffer = new char[10];

        // Copy input into buffer with bounds checking
        for (int i = 0; i < maxLength; i++) {
            buffer[i] = name.charAt(i);
        }

        System.out.println("Hello, " + new String(buffer));
    }
}

